const __pageData = JSON.parse('{"title":"ORM深度：对象-关系阻抗失配","description":"深入剖析对象-关系阻抗失配的六大冲突维度，对比 Active Record、Data Mapper、Unit of Work 等 ORM 模式，并在 JS/TS 生态中映射到 Prisma、TypeORM、Drizzle、Kysely、MikroORM 的具体实现策略。","frontmatter":{"title":"ORM深度：对象-关系阻抗失配","description":"深入剖析对象-关系阻抗失配的六大冲突维度，对比 Active Record、Data Mapper、Unit of Work 等 ORM 模式，并在 JS/TS 生态中映射到 Prisma、TypeORM、Drizzle、Kysely、MikroORM 的具体实现策略。","date":"2026-05-01T00:00:00.000Z","tags":["ORM","Prisma","TypeORM","Drizzle","Kysely","MikroORM","Data Mapper","Active Record","阻抗失配"],"category":"engineering"},"headers":[],"relativePath":"database-orm/02-orm-deep-dive.md","filePath":"database-orm/02-orm-deep-dive.md","lastUpdated":1777741461000}');
